var e=[{id:`L2_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`뭐야. 작전이라더니 간단하네. 그냥 거슬리는 건 다 때려잡으면 된다는 거잖아?`,JPN:`何なの。作戦とはいうけれど簡単であるね。そのまま障るのはすべて殴って捕れば良いということじゃない?`,ENG:`Huh? That's a really simple mission. You just have to smack down everything that gets in your way.`,TWN:`什麼嘛，這作戰太簡單了吧，只要把擋路的傢伙全部幹掉就好了喔？`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`생각없이 무식하게 쏴 갈기기만 하는 것보단, 적재적소에 두뇌도 좀 쓰는 게 낫단 얘기지.`,JPN:`考えなしに無識にざあっとぶん殴るだけにするのよりは、適材適所に頭脳もちょっと使ったほうがましであるという話だ。`,ENG:`It's about using your brain efficiently instead of spraying at everything in sight.`,TWN:`比起隨便亂射一通，妳需要把腦袋用在正確的地方。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`뭐? 방금 한 말...... 잘은 모르겠지만 또 내 욕한 것 같은데......?`,JPN:`何?今一言葉......よく分からないがまた出して悪口を言ったようであるが......?`,ENG:`Huh? What you just said... I didn't really understand it, but were you making fun of me again?`,TWN:`什麼？妳剛才說的話……雖然聽不太懂，但好像又是在損我……`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`XIAOLIN_ALT_NULL_NULL`,text:{KOREA:`이럴 땐 눈치가 좋네. 평소랑은 다르게 말이야.`,JPN:`こうする時は勘が良いね。普段とは違うように。`,ENG:`You noticed? That's unusual of you to catch on so quickly.`,TWN:`在這種時候倒是很敏銳，不像平常。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`XIAOLIN_ALT_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L9_1`,type:`dialog`,speaker:`YOOJIN_ALT_NULL_NULL`,text:{KOREA:`뭐?! 너 지금 뭐라 그랬어! 이리 안 와?!`,JPN:`何?!君今何だとそうだった!このように来ない?!`,ENG:`What?! What did you just say? Get over here!`,TWN:`什麼？！妳剛剛說什麼？過來啊！！`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`YOOJIN_ALT_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`KIMSOBIN_ALT_NULL_NULL`,text:{KOREA:`얘, 얘들아...... 우, 우리 이러지 않기로 우리 약속했잖아......`,JPN:`この子、皆さん......右、私たちのこうしないことに私たちの約束したんじゃないの......`,ENG:`G-guys... W-we promised not to do this again...`,TWN:`各、各位……我們不是說好不要這樣的嗎……`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KIMSOBIN_ALT_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`LENA_COFFIN_NULL_NULL`,text:{KOREA:`음...... 브리핑은 이쯤에서 마치는 게 좋을 것 같네요.`,JPN:`うーん......ブリーフィングはこのくらいで終えるのが良さそうですね。`,ENG:`Um... I guess we should end the briefing here.`,TWN:`嗯……看來我們的簡報就到這邊結束吧。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`LENA_COFFIN_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SEOYOON_ALT_NULL_NULL`,text:{KOREA:`하하, 죄송해요. 돌아가서 제가 잘 타일러 볼게요.`,JPN:`ハハ、申し訳ないです。帰って私がよくたしなめてみますよ。`,ENG:`Hah hah, I'm sorry. I'll have a talk with them after we return.`,TWN:`哈哈，對不起。我回去會好好說說他們的。`},stage:{bg:`WORKSHOP`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SEOYOON_ALT_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};